    def __init__(self, root):
        self.nodes = list(root)

    def insert(self, val):
        self.nodes.append(val)
        k = len(self.nodes) - 1
        parent_idx = (k - 1) // 2
        return self.nodes[parent_idx]

    def get_root(self):
        return list(self.nodes)

