class CBTInserter:
    def __init__(self, root):
        self.tree = list(root)

    def insert(self, val):
        self.tree.append(val)
        idx = len(self.tree) - 1
        parent = (idx - 1) // 2
        return self.tree[parent]

    def get_root(self):
        return self.tree

