class CBTInserter {
    constructor(root) {
        this.tree = root.slice();
    }
    insert(val) {
        this.tree.push(val);
        const idx = this.tree.length - 1;
        const parent = Math.floor((idx - 1) / 2);
        return this.tree[parent];
    }
    get_root() {
        return this.tree;
    }
}
